UPDATE iam_role
   SET deleted = 1,
       deleted_at = NOW(6),
       deleted_by = #{operatorId},
       updated_at = NOW(6),
       version = version + 1
 WHERE tenant_id = #{tenantId}
   AND id = #{roleId}
   AND deleted = 0;
